// CNPJ da empresa que recebe as notas fiscais (usado para validar o destinatário)
const CNPJ_NOSSA_EMPRESA = '33042730000104';
// Prazo máximo, em dias, para aceitar uma nota fiscal
const LIMITE_DIAS_NOTA = 90;

// Pega o texto bruto retornado pela IA a partir do PDF processado
const textoBrutoIA = $json?.output?.[0]?.content?.[0]?.text;
if (!textoBrutoIA) {
  throw new Error('Erro: O texto extraído pela inteligência artificial não foi encontrado.');
}

// Transforma o texto JSON retornado pela IA em objeto JavaScript
let dadosExtraidos;
try {
  dadosExtraidos = JSON.parse(textoBrutoIA);
} catch (erroParse) {
  throw new Error(`Erro de leitura: A resposta da IA não está em formato JSON válido: ${erroParse.message}`);
}

// Remove tudo que não for número (usado em CNPJ e chave de acesso)
function apenasNumeros(valor) {
  if (valor === null || valor === undefined) return null;
  const limpo = String(valor).replace(/\D/g, '');
  return limpo.length > 0 ? limpo : null;
}

// Converte valores em texto no formato brasileiro (ex: "1.250,00") para número
function tratarValorMonetario(valor) {
  if (valor === null || valor === undefined || valor === '') return null;
  if (typeof valor === 'number') return valor;
  const formatado = String(valor).trim().replace(/\./g, '').replace(',', '.');
  const numero = Number(formatado);
  return Number.isFinite(numero) ? numero : null;
}

// Organiza os dados extraídos já limpos e normalizados
const dadosNota = {
  is_invoice: Boolean(dadosExtraidos.is_invoice),
  document_type: dadosExtraidos.document_type ?? null,
  reason: dadosExtraidos.reason ?? null,
  numero_nota: dadosExtraidos.numero_nota ?? null,
  serie: dadosExtraidos.serie ?? null,
  chave_acesso: apenasNumeros(dadosExtraidos.chave_acesso),
  emitente: dadosExtraidos.emitente ?? null,
  cnpj_emitente: apenasNumeros(dadosExtraidos.cnpj_emitente),
  destinatario: dadosExtraidos.destinatario ?? null,
  cnpj_destinatario: apenasNumeros(dadosExtraidos.cnpj_destinatario),
  valor_total: tratarValorMonetario(dadosExtraidos.valor_total),
  data_emissao: dadosExtraidos.data_emissao ?? null,
  data_vencimento: dadosExtraidos.data_vencimento ?? null,
  pedido_id: dadosExtraidos.pedido_id ?? null,
  numero_pedido: dadosExtraidos.numero_pedido ?? null,
  auditoria_status: 'ok',
  auditoria_falha_motivo: null,
};

if (dadosNota.is_invoice) {
  // Verifica se o CNPJ do destinatário foi identificado
  if (!dadosNota.cnpj_destinatario) {
    dadosNota.auditoria_status = 'bloqueado';
    dadosNota.auditoria_falha_motivo = 'CNPJ do destinatário não identificado na nota fiscal.';
  // Verifica se o CNPJ do destinatário é o correto
  } else if (dadosNota.cnpj_destinatario !== CNPJ_NOSSA_EMPRESA) {
    dadosNota.auditoria_status = 'bloqueado';
    dadosNota.auditoria_falha_motivo = `CNPJ Destinatário incorreto. Nota emitida para outro CNPJ (${dadosNota.cnpj_destinatario}).`;
  }

  // Verifica se a nota não está fora do prazo aceito
  if (dadosNota.auditoria_status === 'ok' && dadosNota.data_emissao) {
    const emissao = new Date(dadosNota.data_emissao);
    const hoje = new Date();
    const diasDecorridos = Math.ceil(Math.abs(hoje - emissao) / (1000 * 60 * 60 * 24));
    if (diasDecorridos > LIMITE_DIAS_NOTA) {
      dadosNota.auditoria_status = 'bloqueado';
      dadosNota.auditoria_falha_motivo = `Nota emitida há mais de ${LIMITE_DIAS_NOTA} dias (${diasDecorridos} dias atrás).`;
    }
  }
} else {
  // Se não for nota fiscal, zera os campos que só fazem sentido pra nota fiscal
  dadosNota.numero_nota = null;
  dadosNota.serie = null;
  dadosNota.chave_acesso = null;
  dadosNota.emitente = null;
  dadosNota.cnpj_emitente = null;
  dadosNota.destinatario = null;
  dadosNota.cnpj_destinatario = null;
  dadosNota.valor_total = null;
  dadosNota.data_emissao = null;
  dadosNota.data_vencimento = null;
  dadosNota.pedido_id = null;
  dadosNota.numero_pedido = null;
}

return [{ json: dadosNota }];

