// Tolerância de diferença de valor aceita entre a nota e o pedido
const TOLERANCIA_REAIS = 0.10;
// Busca os pedidos cadastrados para o fornecedor da nota
const pedidosEncontrados = $('Buscar pedidos do fornecedor').all();
const notaFiscal = $('Validar e normalizar NF').first().json;

// Se não veio nenhum pedido do banco, já bloqueia por falta de referência
if (!pedidosEncontrados || pedidosEncontrados.length === 0) {
  return [{
    json: {
      ...notaFiscal,
      match_status: 'pedido_nao_encontrado',
      match_motivo: 'Nenhum pedido de compra foi retornado pelo banco de dados.',
    },
  }];
}

// Pega a referência de pedido informada na nota (se houver)
const pedidoRef = String(notaFiscal.pedido_id || notaFiscal.numero_pedido || '');
let pedidoCorrespondente = null;

// Tenta achar o pedido que bate com a referência da nota
if (pedidoRef) {
  pedidoCorrespondente = pedidosEncontrados.find((item) => {
    const p = item.json;
    return String(p.pedido_id) === pedidoRef || String(p.numero_pedido || '') === pedidoRef;
  })?.json;
}

// Só usa o fallback "fornecedor com 1 pedido só" se esse item for de fato um
// pedido de verdade (tem pedido_id) — não o item vazio que o Supabase devolve
// quando Always Output Data está ligado e a busca não encontra nada.
if (!pedidoCorrespondente && pedidosEncontrados.length === 1 && pedidosEncontrados[0].json.pedido_id) {
  pedidoCorrespondente = pedidosEncontrados[0].json;
}

// Se ainda assim não achou nenhum pedido correspondente, bloqueia
if (!pedidoCorrespondente) {
  return [{
    json: {
      ...notaFiscal,
      match_status: 'pedido_nao_encontrado',
      match_motivo: pedidoRef
        ? 'O pedido de compra informado na nota não existe no nosso sistema.'
        : 'Múltiplos pedidos encontrados para o CNPJ e nenhuma referência de pedido na nota.',
    },
  }];
}

// Compara o valor da nota com o valor esperado do pedido
const valorNota = Number(notaFiscal.valor_total || 0);
const valorPedido = Number(pedidoCorrespondente.valor_esperado || pedidoCorrespondente.valor_total || 0);
const diferencaValores = Math.abs(valorNota - valorPedido);

let matchStatus = 'aprovado';
let matchMotivo = null;

// Divergência acima da tolerância bloqueia; dentro da tolerância, aprova com ressalva
if (diferencaValores > TOLERANCIA_REAIS) {
  matchStatus = 'divergente';
  matchMotivo = `Divergência de valores. Nota: R$ ${valorNota.toFixed(2)} | Pedido: R$ ${valorPedido.toFixed(2)} (diferença R$ ${diferencaValores.toFixed(2)})`;
} else if (diferencaValores > 0) {
  matchMotivo = `Aprovado com tolerância de arredondamento. Diferença aceita de R$ ${diferencaValores.toFixed(2)}.`;
}

// Retorna a nota já com o resultado do match aplicado
return [{
  json: {
    ...notaFiscal,
    valor_pedido: valorPedido,
    pedido_id: pedidoCorrespondente.pedido_id,
    fornecedor_cnpj: pedidoCorrespondente.fornecedor_cnpj || notaFiscal.cnpj_emitente,
    match_status: matchStatus,
    match_motivo: matchMotivo,
  },
}];

